    @Override
    public CheckResult check(String output, String expected) {

        List<String> board = new ArrayList<>(List.of(expected.trim().split("\n\n")));
        if ("Game Over!".equalsIgnoreCase(board.get(board.size() - 1))) {
            board.remove(board.size() - 1);
        }

        List<String> reply_board = new ArrayList<>(List.of(output.trim().split("\n\n")));
        if ("Game Over!".equalsIgnoreCase(reply_board.get(reply_board.size() - 1))) {
            reply_board.remove(reply_board.size() - 1);
        }

        if (board.size() != reply_board.size()) {
            String message = "A field with " + board.size() + " grid" + (board.size() != 1 ? "s" : "") + " is expected to be printed. ";
            if (reply_board.size() == 1 && reply_board.get(0).isEmpty()) {
                return CheckResult.wrong(message + "The output is empty.");
            }

            message += "Found " + reply_board.size() + " grid" + (reply_board.size() != 1 ? "s." : ".");
            return CheckResult.wrong(message);

        }
        List<String[]> line = board.stream().map(
                it -> it.trim().split("\n")
        ).toList();
        List<String[]> line_reply = reply_board.stream().map(
                it -> it.trim().split("\n")
        ).toList();

        if (line.size() != line_reply.size()) {
            return CheckResult.wrong(
                    "A grid with " + line.size() + " rows is expected to be printed. Found " + line_reply.size() + " rows");
        }

        for (int i = 0; i < line.size(); ++i) {
            List<String[]> line_columns = Arrays.stream(line.get(i)).map(
                    it -> it.trim().split(" ")
            ).toList();
            List<String[]> reply_columns = Arrays.stream(line_reply.get(i)).map(
                    it -> it.trim().split(" ")
            ).toList();

            if (line_columns.size() != reply_columns.size()) {
                return CheckResult.wrong(
                        "A grid with " + line_columns.size() + " columns is expected to be printed. Found " + reply_columns.size() + " columns");
            }

            for (String[] one_col : reply_columns) {
                for (String symbol : one_col) {
                    if (!"-".equals(symbol) && !"0".equals(symbol)) {
                        return CheckResult.wrong("The field should contain zero (0) or short-dash (-) symbols. Found " + symbol);
                    }
                }
            }
        }

        for (int i = 0; i < reply_board.size(); ++i) {
            String[] reply_board_per_line = reply_board.get(i).split("\n");
            String[] answer_board_per_line = board.get(i).split("\n");

            for (int j = 0; j < reply_board_per_line.length; ++j) {
                if (reply_board_per_line[j].endsWith(" ")) {
                    reply_board_per_line[j] = reply_board_per_line[j].stripTrailing();
                }
                if (j >= answer_board_per_line.length) {
                    return CheckResult.wrong("Seems like the size of the grid is incorrect");
                }
                if (!reply_board_per_line[j].equals(answer_board_per_line[j])) {
                    return CheckResult.wrong(
                            "Wrong line " + (j + 1) + " in grid " + (i + 1) + ": Should be " + answer_board_per_line[j] + " instead of " + reply_board_per_line[j] + "\nExpected grid:\n" + board.get(i) + "\nYour grid:\n" + reply_board.get(i));
                }
            }
        }
        return CheckResult.correct();
    }
